```python
import numpy as np

class CheckersGame:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.current_player = 1  # Player 1 starts with pieces on dark squares
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = -1
        for i in range(5, 8):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 1

    def print_board(self):
        symbols = {0: '.', -1: 'X', 1: 'O'}
        print('  '.join(str(i) for i in range(8)))
        for row in range(8):
            print(symbols[row[0]], end=' ')
            for piece in row:
                print(symbols[piece], end=' ')
            print()

    def is_valid_move(self, start, end):
        # Simple validation for a move
        return abs(start[0] - end[0]) == 1 and (abs(start[1] - end[1]) == 1 or abs(start[1] - end[1]) == 2)

    def make_move(self, start, end):
        if self.is_valid_move(start, end):
            piece = self.board[start[0], start[1]]
            self.board[end[0], end[1]] = piece
            self.board[start[0], start[1]] = 0
            self.current_player *= -1

    def is_game_over(self):
        # Simple check to see if game is over (more sophisticated logic needed)
        return True

    def main_loop(self):
        while not self.is_game_over():
            self.print_board()
            start = input(f"Player {self.current_player}, enter your move (start-end): ").split('-')
            start, end = tuple(map(int, start)), tuple(map(int, end))
            self.make_move(start, end)

if __name__ == "__main__":
    game = CheckersGame()
    game.main_loop()
```

